3085	import type { CategoryScores, EvalCitation } from "../../types.js";
3086	
3087	function stripFences(s: string): string {
3088	  const match = s.match(/```(?:json)?\s*([\s\S]+?)```/);
3089	  return match ? match[1].trim() : s.trim();
3090	}
3091	
3092	export interface ExtractionResult {
3093	  applicant_name: string | null;
3094	  email: string | null;
3095	  phone: string | null;
3096	  employer: string | null;
3097	  monthly_income: number | null;
3098	  move_in_date: string | null;
3099	}
3100	
3101	export function parseExtractionJson(raw: string): ExtractionResult {
3102	  const obj = JSON.parse(stripFences(raw));
3103	  const fields: (keyof ExtractionResult)[] = [
3104	    "applicant_name",
3105	    "email",
3106	    "phone",
3107	    "employer",
3108	    "monthly_income",
3109	    "move_in_date",
3110	  ];
3111	  const out: ExtractionResult = {
3112	    applicant_name: null,
3113	    email: null,
3114	    phone: null,
3115	    employer: null,
3116	    monthly_income: null,
3117	    move_in_date: null,
3118	  };
3119	  for (const f of fields) {
3120	    if (obj[f] === undefined) continue;
3121	    out[f] = obj[f] === null ? null : (obj[f] as never);
3122	  }
3123	  return out;
3124	}
3125	
3126	export interface EvaluationResult {
3127	  overall_score: number;
3128	  recommendation: "low_risk" | "review" | "high_risk";
3129	  category_scores: CategoryScores;
3130	  summary: string;
3131	  concerns: EvalCitation[];
3132	  verified_facts: EvalCitation[];
3133	}
3134	
3135	const REC_VALUES = ["low_risk", "review", "high_risk"] as const;
3136	const CATEGORIES = ["income", "credit", "history", "identity"] as const;
3137	
3138	export function parseEvaluationJson(raw: string): EvaluationResult {
3139	  const obj = JSON.parse(stripFences(raw));
3140	
3141	  if (typeof obj.overall_score !== "number") {
3142	    throw new Error("missing overall_score");
3143	  }
3144	  if (!REC_VALUES.includes(obj.recommendation)) {
3145	    throw new Error(`invalid recommendation: ${obj.recommendation}`);
3146	  }
3147	  if (!obj.category_scores || typeof obj.category_scores !== "object") {
3148	    throw new Error("missing category_scores");
3149	  }
3150	  for (const cat of CATEGORIES) {
3151	    const cs = obj.category_scores[cat];
3152	    if (!cs || typeof cs.score !== "number" || typeof cs.summary !== "string") {
3153	      throw new Error(`category_scores.${cat} missing or malformed`);
3154	    }
3155	  }
3156	  if (typeof obj.summary !== "string") {
3157	    throw new Error("summary must be a string");
3158	  }
3159	  if (!Array.isArray(obj.concerns)) throw new Error("concerns must be an array");
3160	  if (!Array.isArray(obj.verified_facts)) {
3161	    throw new Error("verified_facts must be an array");
3162	  }
3163	
3164	  return {
3165	    overall_score: Math.round(obj.overall_score),
3166	    recommendation: obj.recommendation,
3167	    category_scores: obj.category_scores,
3168	    summary: obj.summary,
3169	    concerns: obj.concerns.map((c: EvalCitation) => ({
3170	      text: c.text,
3171	      source_document_id: c.source_document_id ?? null,
3172	    })),
3173	    verified_facts: obj.verified_facts.map((c: EvalCitation) => ({
3174	      text: c.text,
3175	      source_document_id: c.source_document_id ?? null,
3176	    })),
3177	  };
3178	}
3179	```
