3195	
3196	### Task G3: Build content blocks from documents
3197	
3198	**Files:**
3199	- Create: `api/src/agents/tenant-eval/build-content.ts`
3200	
3201	The Anthropic SDK accepts an array of content blocks per message — text and images, and PDFs as base64-encoded `application/pdf`. We build that array from `tenant_documents` rows, including the `document_id` so the model can cite.
3202	
3203	- [ ] **Step 1: Create**
3204	
3205	```ts
3206	import { TenantDocument } from "../../types.js";
3207	import { Storage } from "../../storage/local.js";
3208	import pdfParse from "pdf-parse";
3209	
3210	export type ContentBlock =
3211	  | { type: "text"; text: string }
3212	  | { type: "image"; source: { type: "base64"; media_type: string; data: string } }
3213	  | {
3214	      type: "document";
3215	      source: { type: "base64"; media_type: "application/pdf"; data: string };
3216	    };
3217	
3218	export async function buildDocumentBlocks(
3219	  storage: Storage,
3220	  docs: TenantDocument[],
3221	): Promise<ContentBlock[]> {
3222	  const blocks: ContentBlock[] = [];
3223	
3224	  for (const doc of docs) {
3225	    blocks.push({
3226	      type: "text",
3227	      text: `--- Document ---\ndocument_id: ${doc.id}\ncategory: ${doc.category}\nfilename: ${doc.filename}`,
3228	    });
3229	
3230	    const buf = await storage.get(doc.storage_key);
3231	
3232	    if (doc.mime_type === "application/pdf") {
3233	      // Try to extract text for context, AND include the raw PDF for vision/parsing.
3234	      try {
3235	        const parsed = await pdfParse(buf);
3236	        if (parsed.text && parsed.text.trim().length > 0) {
3237	          blocks.push({
3238	            type: "text",
3239	            text: `Extracted text from ${doc.filename}:\n${parsed.text.slice(0, 50_000)}`,
3240	          });
3241	        }
3242	      } catch {
3243	        // pdf-parse failed; fall back to including the raw PDF only
3244	      }
3245	      blocks.push({
3246	        type: "document",
3247	        source: {
3248	          type: "base64",
3249	          media_type: "application/pdf",
3250	          data: buf.toString("base64"),
3251	        },
3252	      });
3253	    } else if (doc.mime_type.startsWith("image/")) {
3254	      blocks.push({
3255	        type: "image",
3256	        source: {
3257	          type: "base64",
3258	          media_type: doc.mime_type,
3259	          data: buf.toString("base64"),
3260	        },
3261	      });
